            raise ValueError('capacity must be positive')
        self.capacity = capacity
        self.buf = [None] * capacity
        self.r = 0
        self.w = 0
        self.size = 0

    def write(self, x):
        self.buf[self.w] = x
        self.w = (self.w + 1) % self.capacity
        if self.size < self.capacity:
            self.size += 1
        else:
            self.r = (self.r + 1) % self.capacity  # advance read on overwrite

